// ============================================================
// NANOCLAW IPC BRIDGE — Validação de Payload
// ============================================================
// Payload esperado (POST body):
//
// Para enviar MENSAGEM:
// {
//   "group":   "main",              // pasta do grupo (ex: main, familia)
//   "type":    "message",
//   "chatJid": "5511999999999@s.whatsapp.net",
//   "text":    "Olá!"
// }
//
// Para AGENDAR TAREFA:
// {
//   "group":          "main",
//   "type":           "schedule_task",
//   "prompt":         "Faça o resumo do dia",
//   "schedule_type":  "cron",         // cron | interval | once
//   "schedule_value": "0 9 * * *",
//   "targetJid":      "5511999999999@s.whatsapp.net",
//   "context_mode":   "isolated"      // isolated | group
// }
//
// Para PAUSAR / RETOMAR / CANCELAR TAREFA:
// {
//   "group":  "main",
//   "type":   "pause_task",   // pause_task | resume_task | cancel_task
//   "taskId": "task-xxx"
// }
//
// Outros tipos suportados: update_task, refresh_groups, register_group
// ============================================================

const body = $input.first().json.body || $input.first().json;

const VALID_TYPES = [
  'message',
  'schedule_task',
  'pause_task',
  'resume_task',
  'cancel_task',
  'update_task',
  'refresh_groups',
  'register_group'
];

// Validação dos campos obrigatórios
if (!body.group) {
  throw new Error('Campo obrigatório faltando: "group" (nome da pasta do grupo, ex: main)');
}
if (!body.type) {
  throw new Error('Campo obrigatório faltando: "type" (tipo do comando IPC)');
}
if (!VALID_TYPES.includes(body.type)) {
  throw new Error(`Tipo desconhecido: "${body.type}". Tipos válidos: ${VALID_TYPES.join(', ')}`);
}

// Validações específicas por tipo
if (body.type === 'message') {
  if (!body.chatJid) throw new Error('type=message requer "chatJid"');
  if (!body.text)    throw new Error('type=message requer "text"');
}
if (body.type === 'schedule_task') {
  if (!body.prompt)         throw new Error('type=schedule_task requer "prompt"');
  if (!body.schedule_type)  throw new Error('type=schedule_task requer "schedule_type" (cron | interval | once)');
  if (!body.schedule_value) throw new Error('type=schedule_task requer "schedule_value"');
  if (!body.targetJid)      throw new Error('type=schedule_task requer "targetJid"');
}
if (['pause_task', 'resume_task', 'cancel_task', 'update_task'].includes(body.type)) {
  if (!body.taskId) throw new Error(`type=${body.type} requer "taskId"`);
}

// Determina subdiretório: messages/ ou tasks/
const subDir = body.type === 'message' ? 'messages' : 'tasks';

// Gera nome de arquivo único
const ts     = Date.now();
const rnd    = Math.random().toString(36).slice(2, 8);
const fileName = `ipc-${ts}-${rnd}.json`;

// Remove o campo "group" do payload IPC (é apenas metadado do workflow)
const { group, ...ipcPayload } = body;

return [{ json: { group, subDir, fileName, ipcPayload } }];

// Monta caminho do arquivo e codifica o conteúdo em base64
// para evitar problemas de escaping ao passar para o shell.

const NANOCLAW_DATA_DIR = '/Users/danilo/Work/Projects/nanoclaw/data';

const { group, subDir, fileName, ipcPayload } = $input.first().json;

const dirPath      = `${NANOCLAW_DATA_DIR}/ipc/${group}/${subDir}`;
const filePath     = `${dirPath}/${fileName}`;
const fileContent  = JSON.stringify(ipcPayload, null, 2);

// Codifica em base64 para passar com segurança ao Execute Command
const fileContentB64 = Buffer.from(fileContent, 'utf8').toString('base64');

return [{ json: { group, subDir, fileName, ipcPayload, dirPath, filePath, fileContentB64 } }];

const cmdResult  = $input.first().json;
const prevData   = $('Montar Caminho IPC').first().json;

const success = cmdResult.exitCode === 0;

return [{
  json: {
    ok:      success,
    message: success
      ? `Comando '${prevData.ipcPayload.type}' enviado ao grupo '${prevData.group}' com sucesso.`
      : `Falha ao escrever arquivo IPC: ${cmdResult.stderr}`,
    type:    prevData.ipcPayload.type,
    group:   prevData.group,
    file:    prevData.fileName,
    path:    prevData.filePath,
    payload: prevData.ipcPayload
  }
}];
